onStart(root, context) {
  const assetHeaders = {
    ".js": "/* eslint-disable */\n",
  };

  [".", "vendor"].forEach((subdir) => {
    const writer = this.getWriter(context);
    const srcDir = path.resolve(__dirname, "assets", subdir);
    fs.readdirSync(srcDir).forEach((f) => {
      const resolvedSource = path.resolve(srcDir, f);
      const resolvedDestination = ".";
      const stat = fs.statSync(resolvedSource);
      let dest;

      if (stat.isFile()) {
        dest = resolvedDestination + "/" + f;
        if (this.verbose) {
          console.log("Write asset: " + dest);
        }
        writer.copyFile(resolvedSource, dest, assetHeaders[path.extname(f)]);
      }
    });
  });
}

insertAt(col, str, insertBefore, consumeBlanks) {
  consumeBlanks =
    typeof consumeBlanks === "undefined" ? this.consumeBlanks : consumeBlanks;
  col = col > this.originalLength() ? this.originalLength() : col;
  col = col < 0 ? 0 : col;

  if (consumeBlanks) {
    if (col <= this.startPos) {
      col = 0;
    }
    if (col > this.endPos) {
      col = this.origLength;
    }
  }

  const len = str.length;
  const offset = this.findOffset(col, len, insertBefore);
  const realPos = col + offset;
  const text = this.text;
  this.text = text.substring(0, realPos) + str + text.substring(realPos);
  return this;
}

function validatePath(
  filePath: unknown,
  pathName: "cache" | "artifacts" | "tests" | "sources",
  index?: number,
): HardhatUserConfigValidationError[] {
  const validationErrors: HardhatUserConfigValidationError[] = [];

  if (typeof filePath !== "string") {
    const messagePrefix =
      index !== undefined
        ? `paths.${pathName} at index ${index}`
        : `paths.${pathName}`;

    validationErrors.push({
      path:
        index !== undefined ? ["paths", pathName, index] : ["paths", pathName],
      message: `${messagePrefix} must be a string`,
    });
  }

  return validationErrors;
}

function validateEmptyTask(
  task: EmptyTaskDefinition,
  path: Array<string | number>,
): HardhatUserConfigValidationError[] {
  const validationErrors: HardhatUserConfigValidationError[] = [];

  if (
    !Array.isArray(task.id) ||
    !task.id.every((id) => typeof id === "string")
  ) {
    validationErrors.push({
      path: [...path, "id"],
      message: "task id must be an array of strings",
    });
  }

  if (typeof task.description !== "string") {
    validationErrors.push({
      path: [...path, "description"],
      message: "task description must be a string",
    });
  }

  return validationErrors;
}

protected async _getRawValue(): Promise<string> {
  const mutex = LazyResolvedConfigurationVariable.#mutexes.get(this.#hooks);
  assertHardhatInvariant(mutex !== undefined, "Mutex must be defined");

  return await mutex.exclusiveRun(
    async () =>
      await this.#hooks.runHandlerChain(
        "configurationVariables",
        "fetchValue",
        [this.#variable],
        async (_context, v) => {
          const value = process.env[v.name];

          if (typeof value !== "string") {
            throw new HardhatError(
              HardhatError.ERRORS.CORE.GENERAL.ENV_VAR_NOT_FOUND,
              { name: v.name },
            );
          }

          return value;
        },
      ),
  );
}

constructor(projectRoot: string, plugins: HardhatPlugin[]) {
  this.#projectRoot = projectRoot;

  for (const plugin of plugins.toReversed()) {
    if (plugin.hookHandlers === undefined) {
      continue;
    }

    for (const hookCategoryName of Object.keys(plugin.hookHandlers) as Array<
      keyof HardhatHooks
    >) {
      if (plugin.hookHandlers[hookCategoryName] === undefined) {
        continue;
      }

      let pluginsForCategory =
        this.#pluginsByHookCategory.get(hookCategoryName);

      if (pluginsForCategory === undefined) {
        pluginsForCategory = [];
        this.#pluginsByHookCategory.set(hookCategoryName, pluginsForCategory);
      }

      pluginsForCategory.push(plugin);
    }
  }
}

async #getHandlersInSequentialRunningOrder<
    HookCategoryNameT extends keyof HardhatHooks,
    HookNameT extends keyof HardhatHooks[HookCategoryNameT],
  >(
    hookCategoryName: HookCategoryNameT,
    hookName: HookNameT,
  ): Promise<Array<HardhatHooks[HookCategoryNameT][HookNameT]>> {
    let handlersByName = this.#sequentialHandlers.get(hookCategoryName);
    if (handlersByName === undefined) {
      handlersByName = new Map();
      this.#sequentialHandlers.set(hookCategoryName, handlersByName);
    }

    const cached = handlersByName.get(hookName as string);
    if (cached !== undefined) {
      return cached;
    }

    const chained = await this.#getHandlersInChainedRunningOrder(
      hookCategoryName,
      hookName,
    );

    const sequential = chained.toReversed();

    handlersByName.set(hookName as string, sequential);

    return sequential;
  }

async #getUserInterruptionManager(): Promise<UserInterruptionManagerImplementationT> {
  // Note: `await import` must run BEFORE the instance cache check so that
  // concurrent callers share a single microtask-dedupe point — otherwise
  // each suspended caller re-enters the branch and constructs its own
  // impl, so callers end up holding different impl instances and state,
  // which can cause concurrency issues.
  if (UserInterruptionManagerImplementation === undefined) {
    ({ UserInterruptionManagerImplementation } = await import(
      "./user-interruptions.js"
    ));
  }

  if (this.#userInterruptionManager === undefined) {
    this.#userInterruptionManager = new UserInterruptionManagerImplementation(
      this.#hooks,
    );
  }

  return this.#userInterruptionManager;
}

constructor(
  hre: HardhatRuntimeEnvironment,
  globalOptionDefinitions: GlobalOptionDefinitions,
) {
  this.#hre = hre;

  // reduce plugin tasks
  for (const plugin of this.#hre.config.plugins) {
    if (plugin.tasks === undefined) {
      continue;
    }

    for (const taskDefinition of plugin.tasks) {
      this.#validateTaskDefinition(taskDefinition, true);
      this.#reduceTaskDefinition(
        globalOptionDefinitions,
        taskDefinition,
        plugin.id,
      );
    }
  }

  // reduce global user defined tasks
  for (const taskDefinition of this.#hre.config.tasks) {
    this.#validateTaskDefinition(taskDefinition, false);
    this.#reduceTaskDefinition(globalOptionDefinitions, taskDefinition);
  }
}

function validateTaskArgumentValue(
  name: string,
  expectedType: ArgumentType,
  value: ArgumentValue | ArgumentValue[],
  isVariadic: boolean,
  taskId: string | string[],
): void {
  try {
    validateArgumentValue(name, expectedType, value, isVariadic);
  } catch (error) {
    if (
      HardhatError.isHardhatError(
        error,
        HardhatError.ERRORS.CORE.ARGUMENTS.INVALID_VALUE_FOR_TYPE,
      )
    ) {
      throw new HardhatError(
        HardhatError.ERRORS.CORE.TASK_DEFINITIONS.INVALID_VALUE_FOR_TYPE,
        {
          name,
          type: expectedType,
          value,
          task: formatTaskId(taskId),
        },
      );
    }

    throw error;
  }
}

resolveUserConfig: async (
  userConfig,
  resolveConfigurationVariable,
  next,
) => {
  const resolvedConfig = await next(
    userConfig,
    resolveConfigurationVariable,
  );

  const defaultKeystoreFilePath = await getKeystoreFilePath();
  const defaultDevKeystoreFilePath = await getDevKeystoreFilePath();
  const defaultDevKeystorePasswordFilePath =
