  log(`path to keystore file: ${defaultKeystoreFilePath}`);

  return {
    ...resolvedConfig,
    keystore: {
      filePath: defaultKeystoreFilePath,
      devFilePath: defaultDevKeystoreFilePath,
      devPasswordFilePath: defaultDevKeystorePasswordFilePath,
    },
  };
}

async function validateLedgerUserConfig(
  userConfig: HardhatUserConfig,
): Promise<HardhatUserConfigValidationError[]> {
  if (userConfig.networks === undefined) {
    return [];
  }

  const networksErrors = [];

  for (const [networkName, network] of Object.entries(userConfig.networks)) {
    const errors = validateUserConfigZodType(
      {
        ledgerAccounts: network.ledgerAccounts,
        ledgerOptions: network.ledgerOptions,
      },
      ledgerUserConfigSchema,
    ).map((err) => {
      err.message = `network "${networkName}" - ${err.message}`;
      return err;
    });

    networksErrors.push(...errors);
  }

  return networksErrors;
}

async function augmentSolxOutputSelectionInProfiles(
  profiles: HardhatConfig["solidity"]["profiles"],
): Promise<HardhatConfig["solidity"]["profiles"]> {
  const result: Record<string, (typeof profiles)[string]> = {};
  for (const [profileName, profile] of Object.entries(profiles)) {
    const augmentedCompilers = await Promise.all(
      profile.compilers.map((compiler) => augmentIfSolx(compiler)),
    );
    const augmentedOverrides: Record<
      string,
      (typeof profile.overrides)[string]
    > = {};
    for (const [overrideKey, override] of Object.entries(profile.overrides)) {
      augmentedOverrides[overrideKey] = await augmentIfSolx(override);
    }
    result[profileName] = {
      ...profile,
      compilers: augmentedCompilers,
      overrides: augmentedOverrides,
    };
  }
  return result;
}

function resolveHttpNetwork(
  networkConfig: HttpNetworkUserConfig,
  resolveConfigurationVariable: ConfigurationVariableResolver,
): HttpNetworkConfig {
  return {
    type: "http",
    accounts: resolveHttpNetworkAccounts(
      networkConfig.accounts,
      resolveConfigurationVariable,
    ),
    chainId: networkConfig.chainId,
    chainType: networkConfig.chainType,
    from: networkConfig.from,
    gas: resolveGasConfig(networkConfig.gas),
    gasMultiplier: networkConfig.gasMultiplier ?? 1,
    gasPrice: resolveGasConfig(networkConfig.gasPrice),
    url: resolveConfigurationVariable(networkConfig.url),
    timeout: networkConfig.timeout ?? 300_000,
    httpHeaders: networkConfig.httpHeaders ?? {},
  };
}

function resolveHttpNetworkAccounts(
  accounts: HttpNetworkAccountsUserConfig | undefined = "remote",
  resolveConfigurationVariable: ConfigurationVariableResolver,
): HttpNetworkAccountsConfig {
  if (Array.isArray(accounts)) {
    return accounts.map((acc) => {
      if (typeof acc === "string") {
        acc = normalizeHexString(acc);
      }

      return resolveConfigurationVariable(acc);
    });
  }

  if (isHttpNetworkHdAccountsUserConfig(accounts)) {
    const { passphrase: defaultPassphrase, ...defaultHdAccountRest } =
      DEFAULT_HD_ACCOUNTS_CONFIG_PARAMS;
    const { mnemonic, passphrase, ...hdAccountRest } = accounts;

    return {
      ...defaultHdAccountRest,
      ...hdAccountRest,
      mnemonic: resolveConfigurationVariable(mnemonic),
      passphrase: resolveConfigurationVariable(passphrase ?? defaultPassphrase),
    };
  }

  return accounts;
}

function resolveForkingConfig(
  forkingUserConfig: EdrNetworkForkingUserConfig | undefined,
  cacheDir: string,
  resolveConfigurationVariable: ConfigurationVariableResolver,
): EdrNetworkForkingConfig | undefined {
  if (forkingUserConfig === undefined) {
    return undefined;
  }

  return {
    enabled: forkingUserConfig.enabled ?? true,
    url: resolveConfigurationVariable(forkingUserConfig.url),
    cacheDir: path.join(cacheDir, "edr-fork-cache"),
    blockNumber:
      forkingUserConfig.blockNumber !== undefined
        ? BigInt(forkingUserConfig.blockNumber)
        : undefined,
    httpHeaders: forkingUserConfig.httpHeaders,
  };
}

async function resolveSolidityUserConfig(
  userConfig: HardhatUserConfig,
  resolvedConfig: HardhatConfig,
): Promise<HardhatConfig> {
  let sourcesPaths = userConfig.paths?.sources;

  // TODO: use isObject when the type narrowing issue is fixed
  sourcesPaths =
    typeof sourcesPaths === "object" && !Array.isArray(sourcesPaths)
      ? sourcesPaths.solidity
      : sourcesPaths;

  sourcesPaths ??= "contracts";

  sourcesPaths = Array.isArray(sourcesPaths) ? sourcesPaths : [sourcesPaths];

  const resolvedPaths = sourcesPaths.map((p) =>
    resolveFromRoot(resolvedConfig.paths.root, p),
  );

  return {
    ...resolvedConfig,
    paths: {
      ...resolvedConfig.paths,
      sources: {
        ...resolvedConfig.paths.sources,
        solidity: resolvedPaths,
      },
    },
    solidity: resolveSolidityConfig(userConfig.solidity ?? "0.8.0"),
  };
}

async function importUserConfig(
  configPath: string,
): Promise<HardhatUserConfig> {
  const normalizedPath = await normalizeConfigPath(configPath);

  const imported = await importConfigFileWithTsxFallback(
    pathToFileURL(normalizedPath).href,
  );

  if (!("default" in imported)) {
    throw new HardhatError(
      HardhatError.ERRORS.CORE.GENERAL.NO_CONFIG_EXPORTED,
      {
        configPath,
      },
    );
  }

  const config = imported.default;

  if (!isObject(config)) {
    throw new HardhatError(
      HardhatError.ERRORS.CORE.GENERAL.INVALID_CONFIG_OBJECT,
      {
        configPath,
      },
    );
  }

  return config;
}

public static isHardhatError(
  other: unknown,
  descriptor?: ErrorDescriptor,
): other is HardhatError<ErrorDescriptor> {
  if (!isObject(other)) {
    return false;
  }

  const isHardhatErrorProperty = Object.getOwnPropertyDescriptor(
    other,
    IS_HARDHAT_ERROR_PROPERTY_NAME,
  );

  return (
    isHardhatErrorProperty?.value === true &&
    // If an error descriptor is provided, check if its number matches the Hardhat error number
    (descriptor === undefined
      ? true
      : "number" in other && other.number === descriptor.number)
  );
}

function applyErrorMessageTemplate(
  template: string,
  values: Record<string, ErrorMessageTemplateValue>,
): string {
  return template.replaceAll(/{(.*?)}/g, (_match, variableName) => {
    const rawValue = values[variableName];

    if (rawValue === undefined) {
      return "undefined";
    }

    if (rawValue === null) {
      return "null";
    }

    if (typeof rawValue === "bigint") {
      return `${rawValue}n`;
    }

    if (Array.isArray(rawValue)) {
      return JSON.stringify(rawValue);
    }

    return rawValue.toString();
  });
}

function overwriteBigNumberWithin(
  _super: (...args: any[]) => any,
  chaiUtils: Chai.ChaiUtils,
) {
  return function (this: Chai.AssertionStatic, ...args: any[]) {
    const [startArg, finishArg] = args;
    const expectedFlag = chaiUtils.flag(this, "object");

    if (isBigInt(expectedFlag) || isBigInt(startArg) || isBigInt(finishArg)) {
      const expected = toBigInt(expectedFlag);
      const start = toBigInt(startArg);
      const finish = toBigInt(finishArg);
      this.assert(
        start <= expected && expected <= finish,
        `expected ${expected} to be within ${start}..${finish}`,
        `expected ${expected} to not be within ${start}..${finish}`,
        expected,
        [start, finish],
      );
    } else {
      _super.apply(this, args);
    }
  };
}

function validateInput(
  obj: any,
  accounts: Array<Addressable | string>,
  balanceChanges: bigint[] | ((changes: bigint[]) => boolean),
) {
  try {
    if (
      Array.isArray(balanceChanges) &&
      accounts.length !== balanceChanges.length
    ) {
      chaiAssert.fail(
        `The number of accounts (${accounts.length}) is different than the number of expected balance changes (${balanceChanges.length})`,
      );
    }
  } catch (e) {
    // if the input validation fails, we discard the subject since it could
    // potentially be a rejected promise
    Promise.resolve(obj).catch(() => {});
    throw e;
  }
}

async function getTxFees(
  accounts: Array<Addressable | string>,
  txResponse: TransactionResponse,
  options?: BalanceChangeOptions,
): Promise<bigint[]> {
  return await Promise.all(
    accounts.map(async (account) => {
      if (
        options?.includeFee !== true &&
        (await getAddressOf(account)) === txResponse.from
      ) {
        const txReceipt = await txResponse.wait();
        assertIsNotNull(
          txReceipt,
          "Transaction's receipt cannot be fetched from the network",
        );
        const gasPrice = txReceipt.gasPrice ?? txResponse.gasPrice;
        const gasUsed = txReceipt.gasUsed;
        const txFee = gasPrice * gasUsed;

        return txFee;
      }

      return 0n;
    }),
  );
}

function validateInput(
  obj: any,
  token: Token,
  accounts: Array<Addressable | string>,
  balanceChanges: bigint[] | ((changes: bigint[]) => boolean),
) {
  try {
    checkToken(token, CHANGE_TOKEN_BALANCES_MATCHER);

    if (
      Array.isArray(balanceChanges) &&
      accounts.length !== balanceChanges.length
    ) {
      chaiAssert.fail(
        `The number of accounts (${accounts.length}) is different than the number of expected balance changes (${balanceChanges.length})`,
      );
    }
  } catch (e) {
    // if the input validation fails, we discard the subject since it could
    // potentially be a rejected promise
    Promise.resolve(obj).catch(() => {});
    throw e;
  }
}
